+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+
+  const page = target.substring(0, headingIndex);
+  const heading = target.substring(headingIndex + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
+
+function convertWikiLinks(text: string, linkStyle: LinkStyleValue, imageStyle: LinkStyleValue): string {
+  if (linkStyle !== 'markdown' && imageStyle !== 'markdown') {
+    return text;
+  }
+
+  return text.replace(/(!)?\\[\\[([^\\]\
]+)\\]\\]/g, (match, embed: string | undefined, contents: string) => {
+    const style = embed ? imageStyle : linkStyle;
+    if (style !== 'markdown') {
+      return match;
+    }
+
+    const displayIndex = contents.indexOf('|');
+    const target = displayIndex === -1 ? contents : contents.substring(0, displayIndex);
+    const display = displayIndex === -1 ? defaultDisplay(target) : contents.substring(displayIndex + 1);
+    if (embed) {
+      // Obsidian uses these display values as image dimensions, not alt text.
+      const alt = display === '300' || /^300x200$/i.test(display) ? target : display;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display}](${target})`;
+  });
+}
