+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  let labelStart = start;
+  if (text[start] === '!') {
+    labelStart++;
+  }
+  if (text[labelStart] !== '[') {
+    return null;
+  }
+
+  let index = labelStart + 1;
+  let depth = 1;
+  for (; index < text.length; index++) {
+    if (text[index] === '\
