+      return null;
+    }
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      break;
+    }
+  }
+  if (depth !== 0 || text[index + 1] !== '(') {
+    return null;
+  }
+
+  const label = text.substring(labelStart + 1, index);
+  const destinationStart = index + 2;
+  index = destinationStart;
+  depth = 1;
+  for (; index < text.length; index++) {
+    if (text[index] === '\
') {
+      return null;
+    }
+    if (text[index] === '\\\') {
+      index++;
+      continue;
+    }
+    if (text[index] === '(') {
+      depth++;
+    } else if (text[index] === ')' && --depth === 0) {
+      break;
+    }
+  }
+  if (depth !== 0) {
+    return null;
+  }
+
+  const destination = text.substring(destinationStart, index);
+  const target = parseDestination(destination);
+  if (target === null || target.includes('://')) {
+    return null;
+  }
