+}
+
+function parseDestination(destination: string): string | null {
+  let index = 0;
+  while (/\\s/.test(destination[index] ?? '')) {
+    index++;
+  }
+  if (destination[index] === '<') {
+    let target = '';
+    index++;
+    for (; index < destination.length; index++) {
+      if (destination[index] === '\\\' && index + 1 < destination.length) {
+        target += destination[++index];
+      } else if (destination[index] === '>') {
+        index++;
